parameters.jsCode:
const item = $input.item.json;
let aiOutput = {};
try {
  const raw = item.output || item.response || item.text || '{}';
  const clean = raw.replace(/```json|```/g, '').trim();
  aiOutput = JSON.parse(clean);
} catch (e) {
  aiOutput = {
    category: 'general_inquiry',
    sensitivityTier: 'SENSITIVE',
    sentimentScore: 0,
    urgencyLevel: 'medium',
    draftReply: 'Thank you for reaching out. A member of our team will be in touch shortly.',
    internalNote: 'AI parsing failed — manual review required.'
  };
}
return {
  json: {
    ...item,
    category: aiOutput.category || 'general_inquiry',
    sensitivityTier: aiOutput.sensitivityTier || 'SENSITIVE',
    sentimentScore: aiOutput.sentimentScore || 0,
    urgencyLevel: aiOutput.urgencyLevel || 'medium',
    draftReply: aiOutput.draftReply || '',
    internalNote: aiOutput.internalNote || '',
    processedAt: new Date().toISOString(),
    processedDate: new Date().toISOString().split('T')[0]
  }
};

