={
  "channel": "#support-escalations",
  "text": ":rotating_light: *Human Review Required* :rotating_light:",
  "blocks": [
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": ":rotating_light: *Human Review Required*\n*From:* {{ $json.customerName }} ({{ $json.sender }})\n*Category:* `{{ $json.category }}`  |  *Urgency:* `{{ $json.urgencyLevel }}`  |  *Sentiment:* `{{ $json.sentimentScore }}`\n*Subject:* {{ $json.subject }}"
      }
    },
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": "*Original Message:*\n{{ ($json.body || '').substring(0, 300) }}"
      }
    },
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": "*AI Draft Reply:*\n{{ ($json.draftReply || '').substring(0, 400) }}"
      }
    },
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": "*Internal Note:* {{ $json.internalNote }}"
      }
    },
    {
      "type": "actions",
      "elements": [
        {
          "type": "button",
          "text": { "type": "plain_text", "text": ":white_check_mark: Approve & Send" },
          "style": "primary",
          "url": "https://your-n8n-instance.com/webhook/support-human-approve?messageId={{ $json.messageId }}&action=approve"
        },
        {
          "type": "button",
          "text": { "type": "plain_text", "text": ":x: Reject Draft" },
          "style": "danger",
          "url": "https://your-n8n-instance.com/webhook/support-human-approve?messageId={{ $json.messageId }}&action=reject"
        }
      ]
    }
  ]
}
